css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { min-height: 100vh; display: flex; align-items: center; justify-content: center; background: radial-gradient(ellipse at top, #2e0a0a 0%, #070b18 60%); padding: 24px; }
.card { width: 100%; max-width: 440px; background: rgba(255,255,255,0.04); border: 1px solid rgba(239,68,68,0.2); border-radius: 24px; padding: 36px; backdrop-filter: blur(20px); box-shadow: 0 30px 60px rgba(0,0,0,0.4); text-align: center; }
.icon-circle { width: 60px; height: 60px; border-radius: 50%; background: linear-gradient(135deg, #ef4444, #b91c1c); display: flex; align-items: center; justify-content: center; margin: 0 auto 20px; color: white; box-shadow: 0 10px 30px rgba(239,68,68,0.35); }
h1 { color: white; font-size: 21px; font-weight: 700; line-height: 1.4; }
.sub { color: rgba(255,255,255,0.5); font-size: 13.5px; line-height: 1.6; margin: 12px 0 22px; }
.warning-box { background: rgba(239,68,68,0.08); border: 1px solid rgba(239,68,68,0.2); border-radius: 14px; padding: 16px 18px; text-align: left; margin-bottom: 20px; }
.warning-title { color: #f87171; font-size: 12.5px; font-weight: 700; margin-bottom: 8px; }
.warning-box ul { list-style: none; display: flex; flex-direction: column; gap: 6px; }
.warning-box li { color: rgba(255,255,255,0.6); font-size: 13px; padding-left: 18px; position: relative; }
.warning-box li::before { content: "•"; position: absolute; left: 0; color: #ef4444; }
.confirm-row { display: flex; align-items: center; gap: 10px; text-align: left; cursor: pointer; margin-bottom: 18px; user-select: none; }
.checkbox { width: 20px; height: 20px; border-radius: 6px; border: 2px solid rgba(255,255,255,0.25); flex-shrink: 0; transition: 0.15s; position: relative; }
.checkbox.checked { background: #ef4444; border-color: #ef4444; }
.checkbox.checked::after { content: "✓"; position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; color: white; font-size: 12px; font-weight: 700; }
.confirm-row span { color: rgba(255,255,255,0.7); font-size: 13px; }
.type-confirm { display: block; text-align: left; color: rgba(255,255,255,0.6); font-size: 13px; margin-bottom: 22px; }
.type-confirm strong { color: #f87171; }
.type-confirm input { display: block; width: 100%; margin-top: 8px; padding: 12px 14px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.05); color: white; font-size: 14px; outline: none; text-align: center; letter-spacing: 0.1em; font-weight: 700; }
.type-confirm input:focus { border-color: #ef4444; }
.actions { display: flex; gap: 10px; }
.btn-secondary { flex: 1; padding: 14px; border: 1px solid rgba(255,255,255,0.12); border-radius: 12px; background: transparent; color: white; font-size: 14px; font-weight: 600; cursor: pointer; }
.btn-danger { flex: 1.4; padding: 14px; border: none; border-radius: 12px; background: linear-gradient(135deg, #ef4444, #b91c1c); color: white; font-size: 14px; font-weight: 700; cursor: pointer; opacity: 0.4; transition: 0.2s; }
.btn-danger:not(:disabled) { opacity: 1; box-shadow: 0 12px 30px rgba(239,68,68,0.3); }
.btn-danger:disabled { cursor: not-allowed; }

js:
const checkbox = document.getElementById('checkbox');
const confirmInput = document.getElementById('confirmInput');
const deleteBtn = document.getElementById('deleteBtn');
let checked = false;

function toggleCheck() {
  checked = !checked;
  checkbox.classList.toggle('checked', checked);
  validate();
}

function validate() {
  deleteBtn.disabled = !(checked && confirmInput.value.trim().toUpperCase() === 'SİL');
}

function cancel() {
  alert('İşlem iptal edildi.');
}

